UPDATE monitor_records
person_name = #{personName}, analysis_result = #{analysisResult}, risk_level = #{riskLevel}, risk_score = #{riskScore}, suggestions = #{suggestions}, update_time = #{updateTime}, update_by = #{updateBy}
WHERE id = #{id} AND deleted = 0

UPDATE monitor_records
SET deleted = 1,
    update_time = NOW(),
    update_by = #{updateBy}
WHERE id = #{id}

