SELECT 
FROM monitor_records

    deleted = 0

        AND person_id = #{personId}


        AND department = #{department}


        AND analysis_type = #{analysisType}


        AND risk_level = #{riskLevel}


        AND create_time >= #{startTime}


        AND create_time <= #{endTime}


ORDER BY create_time DESC
